+    /// Default settings equal themselves.
+    #[test]
+    fn default_settings_eq_self(_dummy in 0u8..1) {
+        let a = CacheGcSettings::default();
+        let b = CacheGcSettings::default();
+        prop_assert!(a == b, "default should equal default");
+    }
